func HasTransactionsWith(preds ...predicate.Transaction) predicate.PaymentSession {
	return predicate.PaymentSession(func(s *sql.Selector) {
		step := newTransactionsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PaymentSession) predicate.PaymentSession {
	return predicate.PaymentSession(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PaymentSession) predicate.PaymentSession {
	return predicate.PaymentSession(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PaymentSession) predicate.PaymentSession {
	return predicate.PaymentSession(sql.NotPredicates(p))
}
